		/*
             SQL ID : AsmntStuIndiDAO.selectObject
             설  명 : 단건 조회
         */			



				AND A.STD_ID = #{stdNo}


				AND A.STD_ID = ( SELECT STD_ID
     							   FROM TB_LMS_ATNDLC_SBJCT
    							  WHERE USER_ID = #{userId}
    								AND ATNDLC_STSCD = 'S'
    								AND SBJCT_ID = #{crsCreCd})

		/*
             SQL ID : AsmntStuIndiDAO.selectsbmsnCnt
             설  명 : 과제제출수
         */		
		SELECT SBMSN_CNT + 1 AS SBMSN_CNT
		  FROM TB_LMS_ASMT_SBMSN
		 WHERE ASMT_ID = #{asmtId}
	       AND ASMT_SBMSN_ID = #{asmtSbmsnId}

mapper.update:
		/*
             SQL ID : AsmntStuIndiDAO.updateTargetSer
             설  명 : 과제 참여자 수정 (교수 제출완료)
         */	
		UPDATE TB_LMS_ASMT_SBMSN A
		JOIN (
			SELECT
				  ASMT_ID
				, ASMT_SBMSN_ID
				, IF(SBMSN_STSCD = 'SUBMIT', 'SUBMIT', #{sbmsnStscd}) AS SBMSN_STSCD
			FROM TB_LMS_ASMT_SBMSN B
			WHERE ASMT_ID = #{asmtId}
			AND ASMT_SBMSN_ID = #{asmtSbmsnId}
		) B
		ON A.ASMT_SBMSN_ID = B.ASMT_SBMSN_ID
			SET A.MDFR_ID = #{userId}
			   , A.MOD_DTTM = FN_DTTM()
			   , A.SBMSN_TXT = #{sbmsnTxt}
			   , A.SBMSN_CTS = #{sbmsnCts}
			   , A.SBMSN_STSCD = B.SBMSN_STSCD
			   , A.SBMSN_CNT = #{sbmsnCnt}
			   , A.CNTN_IP = #{connIp}
		 WHERE A.ASMT_ID = #{asmtId}
	       AND A.ASMT_SBMSN_ID = #{asmtSbmsnId}

		/*
             SQL ID : AsmntStuIndiDAO.revertTarget
             설  명 : 과제 참여자 초기화
         */	
		UPDATE TB_LMS_ASMT_SBMSN
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , SBMSN_TXT = #{sbmsnTxt}
			   , SBMSN_CTS = #{sbmsnCts}
			   , SBMSN_STSCD = #{sbmsnStscd}
			   , SBMSN_CNT = #{sbmsnCnt}
			   , CNTN_IP = #{connIp}
			   , SCR = NULL
			   , EVLYN = 'N'
			   , EXLN_ASMTYN = 'N'
		 WHERE ASMT_ID = #{asmtId}
	       AND ASMT_SBMSN_ID = #{asmtSbmsnId}

		/*
             SQL ID : AsmntStuIndiDAO.updateTargetFile
             설  명 : 과제 제출 파일 정보 수정
         */	
		UPDATE TB_LMS_ASMNT_SBMT_FILE
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
		WHERE ASMT_ID = #{asmtId}
	      AND ASMT_SBMSN_ID = #{asmtSbmsnId}

		/*
             SQL ID : AsmntStuIndiDAO.revertTargetFile
             설  명 : 과제 제출 파일 초기화
         */	
		UPDATE TB_LMS_ASMNT_SBMT_FILE
		   SET MDFR_ID = NULL
			   , MOD_DTTM = NULL
		WHERE ASMT_ID = #{asmtId}
	      AND ASMT_SBMSN_ID = #{asmtSbmsnId}

mapper.select:
		/*
             SQL ID : AsmntStuIndiDAO.selectEval
             설  명 : 상호평가 조회
         */	
		SELECT *
		  FROM TB_LMS_ASMT_MTL_EVL
		 WHERE ASMT_ID = #{asmtId}
	       AND ASMT_SBMSN_ID = #{asmtSbmsnId}
	       AND RGTR_ID = #{userId}

mapper.insert:
		/*
             SQL ID : AsmntStuIndiDAO.insertEval
             설  명 : 상호평가 등록
         */	
		INSERT TB_LMS_ASMT_MTL_EVL (
			ASMT_SBMSN_ID
			, ASMT_ID
			, SCR
			, SCR_CMNT
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES(
			#{asmtSbmsnId}
			, #{asmtId}
			, #{SCR}
			, #{scoreCmnt}
			, #{userId}
			, FN_DTTM()
			, #{userId}
			, FN_DTTM()
		)

mapper.update:
		/*
             SQL ID : AsmntStuIndiDAO.updateEval
             설  명 : 상호평가 수정
         */	
		UPDATE TB_LMS_ASMT_MTL_EVL
		   SET MDFR_ID = #{userId}
			   , MOD_DTTM = FN_DTTM()
			   , SCR = #{SCR}
			   , SCR_CMNT = #{scoreCmnt}
		WHERE ASMT_ID = #{asmtId}
	      AND ASMT_SBMSN_ID = #{asmtSbmsnId}
	      AND RGTR_ID = #{userId}

mapper.select:
/* SQL ID : AsmntStuIndiDAO.selectAsmntJoinUserList 설 명 : 과제 참여자 목록 정보 조회 */ SELECT A.ASMT_SBMSN_ID , A.ASMT_ID , A.STD_ID , A.SBMSN_TYCD , A.TEAM_ID , A.SBMSN_CTS , A.SBMSN_TXT , A.SCR , A.SBMSN_STSCD , A.SBMSN_CNT , A.CNTN_IP , A.EVLYN , A.SCR_MEMO , A.DELYN , A.EXLN_ASMTYN , A.RESEND_YN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , B.USER_ID FROM TB_LMS_ASMT_SBMSN A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND B.SBJCT_ID = #{crsCreCd} AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N'
AND B.USER_ID IN
#{item}
WHERE A.ASMT_ID = #{asmtId} AND A.DELYN = 'N'
